import { Component, createEffect, createSignal, mergeProps, on, onCleanup, Show } from 'solid-js';
import X from 'lucide-solid/icons/x';

import { cn } from '@/utils/cn';
import { ZIndex, ZIndexType } from '../z-index';
import { conditionalRender } from '@/utils/hoc';
import { DrawerType } from './drawer.types';

// Global ESC key handler — shared across all drawer instances (mirrors modal pattern)
const [drawerIds, setDrawerIds] = createSignal<string[]>([]);
const drawerCloseCallbacks = new Map<string, () => void>();

function globalKeyDownHandler(e: KeyboardEvent) {
  if (e.key !== 'Escape') return;
  const topId = drawerIds().at(-1);
  if (topId) drawerCloseCallbacks.get(topId)?.();
}

function registerDrawer(id: string, cb: () => void) {
  if (drawerCloseCallbacks.size === 0) {
    document.addEventListener('keydown', globalKeyDownHandler);
  }
  drawerCloseCallbacks.set(id, cb);
}

function unregisterDrawer(id: string) {
  drawerCloseCallbacks.delete(id);
  if (drawerCloseCallbacks.size === 0) {
    document.removeEventListener('keydown', globalKeyDownHandler);
  }
}

const PANEL_PLACEMENT_CLASS: Record<string, string> = {
  left: 'dr02-left',
  right: 'dr02-right',
  top: 'dr02-top',
  bottom: 'dr02-bottom',
};

const ComponentDrawer: Component<DrawerType> = p => {
  p = mergeProps(
    {
      placement: 'left',
      closeOnOutsideClick: true,
      closable: true,
      mask: true,
      maskBlur: false,
      preRender: false,
      open: false,
      onClose: () => {},
    } as DrawerType,
    p,
  );

  const drawerId = Math.random().toString(36).slice(2);

  createEffect(
    on(
      () => p.open,
      open => {
        if (open) {
          if (drawerId !== drawerIds().at(-1)) {
            setDrawerIds(ids => [...ids, drawerId]);
          }
          registerDrawer(drawerId, () => p.onClose());
        } else {
          unregisterDrawer(drawerId);
          setDrawerIds(ids => ids.filter(id => id !== drawerId));
        }
      },
    ),
  );

  onCleanup(function unregisterDrawerOnUnmount() {
    unregisterDrawer(drawerId);
    setDrawerIds(ids => ids.filter(id => id !== drawerId));
  });

  const isHorizontal = () => p.placement === 'left' || p.placement === 'right';

  const panelStyle = () => {
    const s: Record<string, string> = {};
    if (isHorizontal() && p.width) {
      s['width'] = p.width;
    } else if (!isHorizontal() && p.height) {
      s['height'] = p.height;
    }
    return s;
  };

  const handleOverlayClick = () => {
    if (p.closeOnOutsideClick) p.onClose();
  };

  return (
    <ZIndex
      type={ZIndexType.MODAL}
      open={p.open ?? false}
      blockScroll
      preRender={p.preRender}
      position={{ inset: '0' }}
      class={cn('pointer-events-none', p.class?.wrapper)}
    >
      {/* Backdrop overlay */}
      <Show when={p.mask}>
        <div
          class={cn(p.maskBlur ? 'dr01-blur' : 'dr01', 'pointer-events-auto')}
          onClick={handleOverlayClick}
        />
      </Show>

      {/* Invisible hit-area khi tắt mask nhưng vẫn closeOnOutsideClick */}
      <Show when={!p.mask && p.closeOnOutsideClick}>
        <div class="pointer-events-auto fixed inset-0" onClick={handleOverlayClick} />
      </Show>

      {/* Panel */}
      <div
        class={cn(
          'dr02',
          PANEL_PLACEMENT_CLASS[p.placement!],
          'pointer-events-auto',
          p.class?.panel,
        )}
        style={panelStyle()}
        onClick={e => e.stopPropagation()}
      >
        {/* Close button */}
        <Show when={p.closable}>
          <button class={cn('dr03', p.class?.closeButton)} onClick={p.onClose} aria-label="Close">
            <X size={16} />
          </button>
        </Show>

        {/* Header */}
        <Show when={p.header}>
          <div class={cn('dr04', p.class?.header)}>{p.header as Element}</div>
        </Show>

        {/* Body */}
        <div class={cn('dr05', p.class?.body)}>
          <Show when={p.body}>{p.body as Element}</Show>
        </div>

        {/* Footer */}
        <Show when={p.footer}>
          <div class={cn('dr06', p.class?.footer)}>{p.footer as Element}</div>
        </Show>
      </div>
    </ZIndex>
  );
};

export const Drawer = conditionalRender(ComponentDrawer, { preRender: 'preRender', when: 'open' });
export { ComponentDrawer };
